A debounce function limits how often a function can be executed by delaying its invocation until after a specified wait time has passed since the last call.

```javascript
function debounce(func, delay) {
  let timeoutId;
  return function (...args) {
    clearTimeout(timeout, delay);
    timeoutId = setTimeout(() => func.apply(this, args), delay);
  };
}

// Example: Log search query only after user stops typing for 500ms
const search = (query) => console.log('Searching for:', query);
const debouncedSearch = debounce(search, 500);

// Simulate user typing
debouncedSearch('a');        // No immediate log
debouncedSearch('ap');       // Still no log
debouncedSearch('app');      // Logs "Searching for: app" after 500ms of no new calls
```
